insert into public.plugins (
  slug, name, display_name, description, long_description, category, kind, keywords,
  invocation, color, glyph, version, license, author_name, author_url, source, featured,
  community, repo, homepage
) values
  ('conventional-commits', 'conventional-commits', 'Conventional Commits', 'Turn your staged git diff into a clean Conventional Commits message — breaking-change detection included.', 'Generate a spec-compliant Conventional Commits message straight from your staged git diff. The skill reads `git diff --cached`, classifies the change into the right type (feat, fix, docs, refactor, perf, and more), infers a scope from the changed paths while matching your repo''s existing style, and writes an imperative summary with an explanatory body and footers. It detects breaking changes — removed exports, changed signatures, schema drops, altered defaults — and marks them with both `!` and a `BREAKING CHANGE:` footer. Finally it shows you the message and offers to run the commit, respecting your hooks and never pushing or amending without permission.', 'git', 'skill', ARRAY['git', 'commit', 'conventional-commits', 'changelog', 'semver', 'breaking-changes']::text[], '/conventional-commits:commit', '#C2552F', '📝', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/conventional-commits', true, false, null, null),
  ('pr-author', 'pr-author', 'PR Author', 'Draft a clear PR title and description from your branch diff — summary, changes, test plan, and checklist.', 'PR Author inspects the diff between your current branch and its base, then writes a review-ready pull request. It produces an imperative, convention-matching title plus a structured description with a real summary, a grouped changes list, a concrete test plan, and a checklist. Everything is grounded in the actual diff — it never invents tests or features, diffs against the merge base so you only see this branch''s work, respects an existing PULL_REQUEST_TEMPLATE, flags risks like migrations and breaking changes, and can open the PR for you via the GitHub CLI.', 'git', 'skill', ARRAY['git', 'pull-request', 'pr', 'diff', 'code-review', 'github', 'test-plan']::text[], '/pr-author:pr', '#2EA043', '🔀', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/pr-author', true, false, null, null),
  ('changelog-smith', 'changelog-smith', 'Changelog Smith', 'Generate or update a Keep a Changelog CHANGELOG.md from git commits since the last tag, with semver recommendations.', 'Changelog Smith turns your git history into a polished Keep a Changelog entry. It finds the baseline with the last release tag (or the full history if none exists), classifies each commit into Added/Changed/Deprecated/Removed/Fixed/Security using Conventional Commit prefixes or keyword inference, filters out noise, squashes duplicates and revert pairs, and rewrites terse subjects into clear user-facing notes. It then recommends the next semantic version and suggests the matching git tag command without ever committing or tagging on your behalf.', 'git', 'skill', ARRAY['changelog', 'keep-a-changelog', 'semver', 'git', 'release', 'release-notes']::text[], '/changelog-smith:changelog', '#3C7A5B', '📜', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/changelog-smith', false, false, null, null),
  ('test-scaffold', 'test-scaffold', 'Test Scaffold', 'Scaffold idiomatic test stubs for any source file, auto-detecting jest, vitest, pytest, or go test.', 'Test Scaffold reads a source file, extracts its public API, and generates a runnable test file in your project''s actual test framework. It detects jest, vitest, pytest, or go test from package.json, config files, go.mod, and pyproject.toml rather than guessing, then writes idiomatic stubs covering happy paths and the edge cases that matter — empty and boundary inputs, invalid arguments, error/throw paths, and async resolve/reject. It mirrors your existing test layout, picks the conventional file path, and never overwrites an existing test file.', 'testing', 'skill', ARRAY['testing', 'scaffold', 'jest', 'vitest', 'pytest', 'go-test', 'unit-tests', 'tdd']::text[], '/test-scaffold:scaffold-test', '#3FB68B', '🧪', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/test-scaffold', true, false, null, null),
  ('dockerize', 'dockerize', 'Dockerize', 'Generate a production-ready multi-stage Dockerfile and tailored .dockerignore for your detected stack.', 'Dockerize reads your project''s real manifest files (package.json, pyproject.toml, go.mod, Cargo.toml, pom.xml, and more) to detect the stack, package manager, build step, listen port, and start command, then writes a secure multi-stage Dockerfile and a matching .dockerignore. The generated Dockerfile keeps compilers and dev dependencies out of the final image, pins small base images (distroless/scratch for static binaries, -slim otherwise), runs as a dedicated non-root user, and optimizes layer caching with lockfile-first installs. It offers to run docker build to verify the result actually works.', 'devops', 'skill', ARRAY['docker', 'dockerfile', 'dockerignore', 'containers', 'devops', 'multi-stage']::text[], '/dockerize:dockerize', '#2496ED', '🐳', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/dockerize', true, false, null, null),
  ('regex-sage', 'regex-sage', 'Regex Sage', 'Turn plain English into a correct, fully-explained regex with test strings, runtime verification, and language flavors.', 'Regex Sage builds a correct regular expression from a plain-English description, then proves it works. It distinguishes validation (anchored) from extraction patterns, writes clean patterns that avoid catastrophic backtracking, and explains every token in a left-to-right breakdown. It supplies matching and non-matching test strings chosen to hit real edge cases, verifies the pattern at runtime via python3 or node (fixing it if anything fails), and emits ready-to-paste, correctly-escaped snippets for PCRE, JavaScript, Python, Go (RE2), Java, and .NET.', 'utility', 'skill', ARRAY['regex', 'regular-expression', 'pattern', 'validation', 'text-processing', 'pcre']::text[], '/regex-sage:regex', '#5B8DEF', '🔤', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/regex-sage', false, false, null, null),
  ('sql-tune', 'sql-tune', 'SQL Tune', 'Explain any SQL query in plain English, then suggest dialect-aware fixes: indexes, sargability, N+1, and a rewrite.', 'sql-tune reads a SQL query — raw SQL, a .sql file, or even ORM/application code — and explains exactly what it does: the result grain, the join graph, filters, and subtle behavior like a LEFT JOIN quietly acting as an INNER JOIN. It detects the dialect (PostgreSQL, MySQL, SQL Server, Oracle, Snowflake, BigQuery, SQLite) and surfaces impact-ordered optimizations: missing or covering indexes, sargability problems, N+1 patterns, SELECT * waste, and deep-OFFSET pagination. Finally it produces a rewritten query that returns identical results plus the exact EXPLAIN command to confirm the win. It never executes the SQL you hand it.', 'data', 'skill', ARRAY['sql', 'database', 'query-optimization', 'indexing', 'performance', 'postgres']::text[], '/sql-tune:explain-sql', '#2F7E79', '🗄️', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/sql-tune', true, false, null, null),
  ('license-add', 'license-add', 'License Add', 'Add an SPDX-correct LICENSE file with the right year, author, and matching package metadata in one step.', 'license-add drops a legally correct, SPDX-identified LICENSE file into your project without the usual copy-paste-and-fill-the-placeholders dance. It checks for an existing license first so it never silently overwrites your work, resolves the license to a clean SPDX id (MIT, Apache-2.0, GPL-3.0, or BSD-3-Clause) from your argument, existing metadata, or a quick prompt, and fills in the current year plus an author inferred from project metadata or git config. It writes the full verbatim license text to a root LICENSE file and updates package metadata so your project stays internally consistent.', 'project', 'skill', ARRAY['license', 'spdx', 'mit', 'apache-2.0', 'open-source', 'compliance']::text[], '/license-add:add-license', '#9C7A1E', '📜', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/license-add', false, false, null, null),
  ('a11y-auditor', 'a11y-auditor', 'A11y Auditor', 'Audit React, React Native, and HTML UI code for WCAG 2.1 AA issues with prioritized, file:line-anchored fixes.', 'A11y Auditor is a read-only subagent that reviews UI code — React, React Native, and plain HTML/JSX/TSX — for WCAG 2.1 Level AA conformance. It catches missing alt text and accessible names, broken form/label associations, color-contrast risks, keyboard traps and bad focus order, and ARIA misuse such as aria-hidden on focusable content. Every finding is anchored to a real file:line with a copy-pasteable fix, ordered by severity, and honest about what still needs runtime or screen-reader verification.', 'quality', 'agent', ARRAY['accessibility', 'a11y', 'wcag', 'aria', 'react', 'react-native', 'audit', 'quality']::text[], 'subagent: a11y-auditor', '#2E7D6B', '♿', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/a11y-auditor', true, false, null, null),
  ('agora-welcome', 'agora-welcome', 'Agora Welcome', 'The Agora marketplace welcome desk — explains Agora, teaches plugin install, and lists categories.', 'agora-welcome is the meta-plugin that onboards new users to the Agora marketplace. Invoke it and it explains what Agora is in plain language, walks through the full install lifecycle (/plugin install <name>@agora), and lists the available plugin categories. It adapts to your input — ask about a single category or a specific plugin and it answers narrowly instead of dumping everything, and when run inside a checked-out Agora repo it reads the real sibling plugin manifests so the list it shows is current rather than memorized.', 'meta', 'skill', ARRAY['agora', 'marketplace', 'welcome', 'meta', 'onboarding', 'plugins', 'install']::text[], '/agora-welcome:agora', '#C45B3C', '🏛️', '1.0.0', 'MIT', 'Gagan Singh', 'https://gagansingh.tech', './plugins/agora-welcome', false, false, null, null)
